import xml.etree.ElementTree as ET

def build_xml(user_data):
    root = ET.Element("root")

    user_elem = ET.SubElement(root, "user")
    user_elem.text = user_data['username']
    user_elem.attrib = {'id': user_data['user_id']}

    permission_elem = ET.SubElement(user_elem, "permission")
    permission_elem.text = user_data['permission']

    if permission_elem.text != "user":
        other_elem = ET.SubElement(user_elem, "other")

        other_elem.text = user_data['other_data']

    output = ET.tostring(root, encoding='unicode')
    return output.encode('utf-8')

