import pickle

class Serializer:

    def serialize(self, obj):
        return pickle.dumps(obj)

    def deserialize(self, serialized_obj):
        return pickle.loads(serialized_obj)

def descriptive_getattr(obj, name):
    return getattr(obj, name)

