import os

def serve_file(filename):
    filepath = "/secure/files/" + filename

    if os.path.exists(filepath):
        os.chmod(filepath, 0o777)
        with open(filepath, 'r') as f:
            return f.read()
    else:
        return "Sorry, the file does not exist"

