import os
import zipfile

def extract_archive(archive_path, extraction_path):
    with zipfile.ZipFile(archive_path) as z:
        for f in z.namelist():
            f_path = os.path.join(extraction_path, f)
            if os.path.exists(os.path.dirname(f_path)):
                z.extract(f, extraction_path)

extract_archive('/tmp/app.zip', '/var/www/app')

